#!/usr/bin/env node
/**
 * sync-validation-status.mjs — derive a validation checklist from a URL report.
 *
 * Reads a report produced by `check-urls.mjs --json` and the catalog, then writes
 * an auto-generated checklist marking each author [x] (no broken URLs in the report)
 * or [ ] (one or more broken). This keeps a status file in sync with reality instead
 * of drifting like a hand-maintained list.
 *
 * Note: a report only lists *broken* URLs, so any author absent from `broken[]` is
 * treated as clean. Run `check-urls.mjs --json` over the whole catalog (no author
 * filter) before syncing for the result to be meaningful.
 *
 * Usage:
 *   node scripts/sync-validation-status.mjs [report.json] [--out path]
 *   # report  default: scripts/data/url-report.json
 *   # --out   default: authors-validation-status.txt
 */
import { readdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const authorsDir = path.join(root, 'public', 'catalog', 'authors');

const args = process.argv.slice(2);
const outIdx = args.indexOf('--out');
const outPath = path.resolve(
  root,
  outIdx !== -1 ? args[outIdx + 1] : 'authors-validation-status.txt',
);
const reportArg = args.find((a, i) => !a.startsWith('--') && i !== outIdx + 1);
const reportPath = path.resolve(root, reportArg || 'scripts/data/url-report.json');

async function main() {
  const report = JSON.parse(await readFile(reportPath, 'utf8'));
  const brokenByAuthor = new Map();
  for (const b of report.broken || []) {
    brokenByAuthor.set(b.authorId, (brokenByAuthor.get(b.authorId) || 0) + 1);
  }

  const files = (await readdir(authorsDir)).filter((f) => f.endsWith('.json'));
  const authors = [];
  for (const file of files.sort()) {
    const authorId = file.replace(/\.json$/, '');
    const data = JSON.parse(await readFile(path.join(authorsDir, file), 'utf8'));
    authors.push({ authorId, count: (data.paintings || []).length });
  }

  const brokenAuthors = authors.filter((a) => brokenByAuthor.has(a.authorId));
  const lines = [
    '# Validation status — AUTO-GENERATED by scripts/sync-validation-status.mjs',
    `# Source report: ${path.relative(root, reportPath)} (generated ${report.generated})`,
    '# Do not edit by hand; re-run the sync script to refresh.',
    '#',
    `# ${authors.length - brokenAuthors.length}/${authors.length} authors clean, ` +
      `${brokenAuthors.length} with broken URLs.`,
    '',
  ];
  for (const a of authors) {
    const broken = brokenByAuthor.get(a.authorId);
    const mark = broken ? '[ ]' : '[x]';
    const note = broken ? ` — ${broken} broken URL${broken === 1 ? '' : 's'}` : '';
    lines.push(`${mark} ${a.authorId} (${a.count} paintings)${note}`);
  }

  await writeFile(outPath, `${lines.join('\n')}\n`);
  console.log(
    `Wrote ${path.relative(root, outPath)}: ` +
      `${authors.length - brokenAuthors.length}/${authors.length} clean.`,
  );
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
